import * as s3 from '@aws-cdk/aws-s3';

import * as cdk from '@aws-cdk/core';


class MyEncryptionStack extends cdk.Stack {

  constructor(scope: cdk.Construct, id: string, props?: cdk.StackProps) {

    super(scope, id, props);


    const bucket = new s3.Bucket(this, 'MyEncryptedBucket', {

      removalPolicy: cdk.RemovalPolicy.DESTROY, // Be careful with this in production

      serverSideEncryptionConfiguration: {

        rules: [

          {

            applyServerSideEncryptionByDefault: new s3.ServerSideEncryptionByDefault({

              sseAlgorithm: s3.ServerSideEncryption.AWS_KMS_MANAGED,

              // You can also use s3.ServerSideEncryption.AWS_KMS_KEY_ID if you have a specific KMS key

            }),

          },

        ],

      },

    });

  }

}


const app = new cdk.App();

new MyEncryptionStack(app, 'MyEncryptionStack');

```


In this example, we create a new S3 bucket with server-side encryption enabled using the AWS KMS managed key. The `removalPolicy` is set to `DESTROY` for demonstration purposes, but you should be careful with this setting in a production environment as it will delete the bucket when the stack is destroyed. You can also specify a particular KMS key ID if you prefer to use a custom KMS key for encryption.

