               token = s.dumps(email, salt='password-reset-salt')
               reset_url = url_for('reset_with_token', token=token, _external=True)
               msg = Message('Password Reset Request', recipients=[email])
               msg.body = f'Please click the link to reset your password: {reset_url}'
               mail.send(msg)
               flash('A password reset email has been sent. Please check your inbox.')
               return redirect(url_for('index'))
           else:
               flash('Email not found.')
       return render_template('reset.html')

   @app.route('/reset/<token>')
   def reset_with_token(token):
       try:
           email = s.loads(token, salt='password-reset-salt', max_age=3600)
       except SignatureExpired:
           return '<h1>The token is expired!</h1>'
       return render_template('reset_with_token.html', token=token)

   @app.route('/reset/<token>/new', methods=['GET', 'POST'])
   def reset_with_token_new(token):
       try:
           email = s.loads(token, salt='password-reset-salt', max_age=3600)
       except SignatureExpired:
           return '<h1>The token is expired!</h1>'
       if request.method == 'POST':
           new_password = request.form['password']
           users[email] = generate_password_hash(new_password)
           flash('Your password has been updated.')
           return redirect(url_for('index'))
       return render_template('reset_with_token_new.html', token=token)

   if __name__ == '__main__':
       app.run(debug=True)

import xml.etree.ElementTree as ET

def read_config(xml_file):
    tree = ET.parse(xml_file)
    root = tree.getroot()

    config = {}
    for child in root:
        config[child.tag] = child.text

    return config

config = read_config('config.xml')
print(config)
